css:
/* Edited by Ernest on 10 July 2025 */

.card {
  font-family: times;
  font-size: 20 px;
  text-align: left;  /* 这里修改：从 center 改为 justify */
  text-justify: inter-word; /* 新增：这能让英文单词间的间距更自然 */
  color: black;
  line-height: normal;

  /* 强烈建议加上下面这三行，防止电脑全屏时文字拉得太长难以阅读 */
  max-width: 700px;     /* 限制最大宽度 */
  margin: 0 auto;       /* 让整个卡片在屏幕中间 */
  padding: 0 15px;      /* 防止文字紧贴手机屏幕边缘 */
}

.note-field {
  font-size: 16px;
  color: #666;
  font-style: italic;
  background-color: #f5f5f5;
  padding: 10px;
  margin-top: 20px;
  border-left: 3px solid #ccc;
  text-align: left;
}

.paraphrase {
  font-style: italic;       /* 斜体 */
  font-size: 18px;
  color: #888888;            /* 浅灰色，你也可以根据需要调浅或深 */
}

h1 {
  font-family: times;
  font-size: 15px;
  font-weight: 600;
  letter-spacing: 5px;
  text-align: center;
  height: 35px;
  line-height: 35px;
  padding: 1px 0px 0px 0px;
  border: 0px solid #b7d5eb;
  border-radius:30px;
}

/* Color and background settings for different categories */
.R { color: #b7d5eb; background-color: #338eca }
.S { color: #c1e7b8; background-color: #56a844 }
.D { color: #f7c4b8; background-color: #ec6c4f }

/* Background color and line-height settings for parts of speech */
.POSR { background-color: #338eca; line-height: 30px;}
.POSS { background-color: #56a844; line-height: 30px; }
.POSD { background-color: #ec6c4f; line-height: 30px; }

/* Styling for horizontal lines */

hr {
  height: 2px;
  border-radius:3px;
  width:40%;
  display:inline-block;
  border:0px solid #ffffff;
}
